import React, { useState, useCallback } from 'react';
import useIsMobile from '../hooks/useIsMobile';
import useRegions from '../hooks/useRegions';
import InfoTooltip from '../components/InfoTooltip';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import s from './BotBuilderPage.module.css';

// ── Indicator Catalogue ─────────────────────────────────────────────────────

const INDICATORS = [
  { key: 'RSI', label: 'RSI (Relative Strength Index)', category: 'Momentum', defaultPeriod: 14, range: [0, 100], description: 'Measures speed and change of price movements. Overbought >70, oversold <30.' },
  { key: 'SMA', label: 'SMA (Simple Moving Average)', category: 'Trend', defaultPeriod: 20, description: 'Average closing price over N periods. Signals trend direction.' },
  { key: 'EMA', label: 'EMA (Exponential Moving Average)', category: 'Trend', defaultPeriod: 12, description: 'Weighted moving average favoring recent prices. Faster response than SMA.' },
  { key: 'MACD', label: 'MACD', category: 'Momentum', description: 'Difference between 12 and 26 EMA. Signal line crossovers indicate entry/exit.' },
  { key: 'MACD_SIGNAL', label: 'MACD Signal Line', category: 'Momentum', description: '9-period EMA of MACD line. Used for crossover signals.' },
  { key: 'MACD_HIST', label: 'MACD Histogram', category: 'Momentum', description: 'Difference between MACD and signal line. Positive = bullish momentum.' },
  { key: 'BB_UPPER', label: 'Bollinger Band Upper', category: 'Volatility', defaultPeriod: 20, description: 'SMA + 2 standard deviations. Price near upper = potentially overbought.' },
  { key: 'BB_LOWER', label: 'Bollinger Band Lower', category: 'Volatility', defaultPeriod: 20, description: 'SMA - 2 standard deviations. Price near lower = potentially oversold.' },
  { key: 'BB_WIDTH', label: 'Bollinger Band Width', category: 'Volatility', defaultPeriod: 20, description: 'Distance between upper and lower bands. Narrow = low volatility (squeeze).' },
  { key: 'ATR', label: 'ATR (Average True Range)', category: 'Volatility', defaultPeriod: 14, description: 'Average range of price movement. Used for stop-loss sizing.' },
  { key: 'VOLUME', label: 'Volume', category: 'Volume', description: 'Number of shares traded. High volume confirms price moves.' },
  { key: 'VOLUME_SMA', label: 'Volume SMA', category: 'Volume', defaultPeriod: 20, description: 'Average volume over N periods. Compare current volume to detect unusual activity.' },
  { key: 'VWAP', label: 'VWAP', category: 'Volume', description: 'Volume-Weighted Average Price. Institutional benchmark for the trading day.' },
  { key: 'STOCH_K', label: 'Stochastic %K', category: 'Momentum', defaultPeriod: 14, range: [0, 100], description: 'Shows price position relative to high-low range. Overbought >80, oversold <20.' },
  { key: 'STOCH_D', label: 'Stochastic %D', category: 'Momentum', defaultPeriod: 3, range: [0, 100], description: '3-period SMA of %K. Crossovers signal momentum changes.' },
  { key: 'ADX', label: 'ADX (Avg Directional Index)', category: 'Trend', defaultPeriod: 14, range: [0, 100], description: 'Measures trend strength (not direction). >25 = trending, <20 = ranging.' },
  { key: 'CCI', label: 'CCI (Commodity Channel Index)', category: 'Momentum', defaultPeriod: 20, description: 'Measures deviation from average price. >100 = overbought, <-100 = oversold.' },
  { key: 'OBV', label: 'OBV (On-Balance Volume)', category: 'Volume', description: 'Cumulative volume indicator. Rising OBV confirms price uptrend.' },
  { key: 'PRICE', label: 'Price (Close)', category: 'Price', description: 'Current closing price of the asset.' },
  { key: 'PRICE_CHANGE_PCT', label: 'Price Change %', category: 'Price', description: 'Percentage change in price over the period.' },
];

const OPERATORS = [
  { key: 'gt', label: '>', description: 'Greater than' },
  { key: 'gte', label: '>=', description: 'Greater than or equal' },
  { key: 'lt', label: '<', description: 'Less than' },
  { key: 'lte', label: '<=', description: 'Less than or equal' },
  { key: 'crosses_above', label: 'Crosses Above', description: 'Value crosses from below to above target' },
  { key: 'crosses_below', label: 'Crosses Below', description: 'Value crosses from above to below target' },
];

const TARGET_TYPES = [
  { key: 'value', label: 'Fixed Value' },
  { key: 'indicator', label: 'Another Indicator' },
];

const POSITION_SIZING = [
  { key: 'fixed_pct', label: 'Fixed % of Equity', description: 'Risk a fixed percentage of total equity per trade' },
  { key: 'fixed_amount', label: 'Fixed Dollar Amount', description: 'Use a fixed dollar amount per trade' },
  { key: 'kelly', label: 'Kelly Criterion', description: 'Optimal position size based on win rate and payoff ratio' },
  { key: 'equal_weight', label: 'Equal Weight', description: 'Divide equity equally among all positions' },
];

const TIME_FILTERS = [
  { key: 'any', label: 'Any Time' },
  { key: 'market_open', label: 'First 30 min (9:30-10:00)' },
  { key: 'mid_day', label: 'Mid-Day (10:00-15:00)' },
  { key: 'power_hour', label: 'Power Hour (15:00-16:00)' },
  { key: 'pre_market', label: 'Pre-Market (4:00-9:30)' },
  { key: 'after_hours', label: 'After-Hours (16:00-20:00)' },
];

// ── Blank condition template ────────────────────────────────────────────────

function blankCondition() {
  return {
    id: Math.random().toString(36).slice(2, 9),
    indicator: 'RSI',
    period: 14,
    operator: 'lt',
    targetType: 'value',
    targetValue: 30,
    targetIndicator: 'SMA',
    targetPeriod: 20,
  };
}

function blankExitCondition() {
  return {
    id: Math.random().toString(36).slice(2, 9),
    indicator: 'RSI',
    period: 14,
    operator: 'gt',
    targetType: 'value',
    targetValue: 70,
    targetIndicator: 'SMA',
    targetPeriod: 20,
  };
}

// ── Condition Row Component ─────────────────────────────────────────────────

function ConditionRow({ cond, onChange, onRemove, index, logic, onLogicChange }) {
  const ind = INDICATORS.find(i => i.key === cond.indicator);

  return (
    <div className={s.conditionColumn}>
      {index > 0 && (
        <div className={s.logicRow}>
          <button
            onClick={() => onLogicChange(logic === 'AND' ? 'OR' : 'AND')}
            className={s.logicBtn}
            style={{
              background: logic === 'AND'
                ? 'color-mix(in srgb, var(--color-blue, #60A5FA) 12%, transparent)'
                : 'color-mix(in srgb, var(--color-amber, #F59E0B) 12%, transparent)',
              color: logic === 'AND'
                ? 'var(--color-blue, #60A5FA)'
                : 'var(--color-amber, #F59E0B)',
            }}
          >
            {logic}
          </button>
          <div className={s.logicDivider} />
        </div>
      )}
      <div className={s.conditionRow}>
        {/* Indicator */}
        <div className={s.fieldIndicator}>
          <label className={s.label}>Indicator</label>
          <select
            value={cond.indicator}
            onChange={e => {
              const newInd = INDICATORS.find(i => i.key === e.target.value);
              onChange({ ...cond, indicator: e.target.value, period: newInd?.defaultPeriod || cond.period });
            }}
            className={s.select}
          >
            {Object.entries(
              INDICATORS.reduce((acc, i) => { (acc[i.category] = acc[i.category] || []).push(i); return acc; }, {})
            ).map(([cat, items]) => (
              <optgroup key={cat} label={cat}>
                {items.map(i => <option key={i.key} value={i.key}>{i.label}</option>)}
              </optgroup>
            ))}
          </select>
        </div>

        {/* Period */}
        {ind?.defaultPeriod && (
          <div className={s.fieldPeriod}>
            <label className={s.label}>Period</label>
            <input
              type="number" min={1} max={200}
              value={cond.period}
              onChange={e => onChange({ ...cond, period: +e.target.value })}
              className={s.input}
            />
          </div>
        )}

        {/* Operator */}
        <div className={s.fieldOperator}>
          <label className={s.label}>Condition</label>
          <select
            value={cond.operator}
            onChange={e => onChange({ ...cond, operator: e.target.value })}
            className={s.select}
          >
            {OPERATORS.map(o => <option key={o.key} value={o.key}>{o.label} {o.description}</option>)}
          </select>
        </div>

        {/* Target type */}
        <div className={s.fieldTarget}>
          <label className={s.label}>Compare To</label>
          <select
            value={cond.targetType}
            onChange={e => onChange({ ...cond, targetType: e.target.value })}
            className={s.select}
          >
            {TARGET_TYPES.map(t => <option key={t.key} value={t.key}>{t.label}</option>)}
          </select>
        </div>

        {/* Target value or indicator */}
        {cond.targetType === 'value' ? (
          <div className={s.fieldValue}>
            <label className={s.label}>Value</label>
            <input
              type="number" step="any"
              value={cond.targetValue}
              onChange={e => onChange({ ...cond, targetValue: +e.target.value })}
              className={s.input}
            />
          </div>
        ) : (
          <>
            <div className={s.fieldTargetIndicator}>
              <label className={s.label}>Target Indicator</label>
              <select
                value={cond.targetIndicator}
                onChange={e => onChange({ ...cond, targetIndicator: e.target.value })}
                className={s.select}
              >
                {INDICATORS.map(i => <option key={i.key} value={i.key}>{i.label}</option>)}
              </select>
            </div>
            <div className={s.fieldPeriod}>
              <label className={s.label}>Period</label>
              <input
                type="number" min={1} max={200}
                value={cond.targetPeriod}
                onChange={e => onChange({ ...cond, targetPeriod: +e.target.value })}
                className={s.input}
              />
            </div>
          </>
        )}

        {/* Remove */}
        <button
          onClick={onRemove}
          title="Remove condition"
          className={s.removeBtn}
        >
          x
        </button>
      </div>
      {ind?.description && (
        <div className={s.conditionHint}>
          {ind.description}
        </div>
      )}
    </div>
  );
}

// ── Strategy Summary (preview what was built) ───────────────────────────────

function StrategySummary({ config }) {
  const describeCondition = (c) => {
    const ind = INDICATORS.find(i => i.key === c.indicator);
    const op = OPERATORS.find(o => o.key === c.operator);
    const indLabel = ind ? `${ind.key}(${c.period || ''})` : c.indicator;
    if (c.targetType === 'value') {
      return `${indLabel} ${op?.label || c.operator} ${c.targetValue}`;
    }
    const tInd = INDICATORS.find(i => i.key === c.targetIndicator);
    return `${indLabel} ${op?.label || c.operator} ${tInd?.key || c.targetIndicator}(${c.targetPeriod || ''})`;
  };

  const entryStr = config.entryConditions.map((c, i) => {
    const prefix = i > 0 ? ` ${config.entryLogic[i - 1] || 'AND'} ` : '';
    return prefix + describeCondition(c);
  }).join('');

  const exitStr = config.exitConditions.map((c, i) => {
    const prefix = i > 0 ? ` ${config.exitLogic[i - 1] || 'AND'} ` : '';
    return prefix + describeCondition(c);
  }).join('');

  return (
    <div className={s.card}>
      <div className={s.summaryTitle}>Strategy Summary</div>
      <div className={s.summaryColumn}>
        <div>
          <span className={s.summaryLabelEntry}>ENTRY</span>
          <div className={s.summaryCode}>
            {entryStr || 'No entry conditions defined'}
          </div>
        </div>
        <div>
          <span className={s.summaryLabelExit}>EXIT</span>
          <div className={s.summaryCode}>
            {exitStr || 'No exit conditions defined'}
          </div>
        </div>
        {config.stopLoss > 0 && (
          <div className={s.summaryStopLoss}>
            Stop Loss: {config.stopLoss}% | Take Profit: {config.takeProfit > 0 ? `${config.takeProfit}%` : 'None'}
          </div>
        )}
        <div className={s.summaryMeta}>
          Position Sizing: {POSITION_SIZING.find(p => p.key === config.positionSizing)?.label || config.positionSizing}
          {config.positionSizeValue > 0 ? ` (${config.positionSizeValue}${config.positionSizing === 'fixed_pct' || config.positionSizing === 'kelly' ? '%' : ''})` : ''}
          {' | '}Max Positions: {config.maxPositions}
          {' | '}Time Filter: {TIME_FILTERS.find(t => t.key === config.timeFilter)?.label || 'Any'}
        </div>
      </div>
    </div>
  );
}

